from typing import Optional, Tuple


def parse_message(raw: str) -> Tuple[str, Optional[str]]:
    """Parse raw message into (command, args) tuple.

    Messages starting with / are treated as commands.
    Other messages default to the 'echo' command.
    """
    raw = raw.strip()
    if not raw.startswith('/'):
        return ('echo', raw)
    parts = raw[1:].split(' ', 1)
    command = parts[0].lower()
    args = parts[1] if len(parts) > 1 else None
    return (command, args)

from typing import Optional
from .parser import parse_message


class MessageHandler:
    def handle(self, raw_message: str) -> str:
        command, args = parse_message(raw_message)
        if command == 'help':
            return 'Available commands: help, echo, calc'
        elif command == 'echo':
            return args or ''
        elif command == 'calc':
            return str(self._evaluate(args))
        return f'Unknown command: {command}'
